const invoer = $('Aangeroepen als tool').first().json;
const actie = String(invoer.actie || 'alles').toLowerCase().trim();
const zoekterm = String(invoer.zoekterm || '').toLowerCase().trim();

let rijen = $input.all().map(i => i.json).filter(r => r && r.product);
if (!rijen.length) {
  return [{ json: { resultaat: 'Er zijn (nog) geen aanbiedingen bekend. De aanbiedingen-workflow haalt ze wekelijks op; je kunt hem ook handmatig draaien.' } }];
}

// Alleen de meest recente ophaalronde gebruiken
const laatste = rijen.map(r => String(r.opgehaald_op || '')).sort().pop();
rijen = rijen.filter(r => String(r.opgehaald_op || '') === laatste);

if (actie === 'zoeken' && zoekterm) {
  rijen = rijen.filter(r => String(r.product).toLowerCase().includes(zoekterm));
  if (!rijen.length) {
    return [{ json: { resultaat: `Geen aanbiedingen gevonden voor '${zoekterm}' (bij AH en Plus, week van ${laatste}).` } }];
  }
}

const max = 40;
const regels = rijen.slice(0, max).map(r => {
  const delen = [`• [${r.winkel}] ${r.product}`];
  if (r.korting) delen.push(String(r.korting));
  if (r.prijs) delen.push(`€${r.prijs}`);
  return delen.join(' — ');
});
let resultaat = `Aanbiedingen (opgehaald op ${laatste}):\n${regels.join('\n')}`;
if (rijen.length > max) {
  resultaat += `\n… en nog ${rijen.length - max} andere aanbiedingen.`;
}
return [{ json: { resultaat } }];
